 {"id":"bd-1tv1","title":"TEST: Host Resilience Unit/Integration Tests","description":"# TEST: Host Resilience Unit/Integration Tests

## Goal
Comprehensive test coverage for circuit breakers, bulkheads, and health-based routing.

## Unit Tests

```rust
#[tokio::test]
async fn test_circuit_breaker_opens_after_failures() {
    let cb = CircuitBreaker::new(CircuitBreakerConfig {
        failure_threshold: 3,
        success_threshold: 2,
        open_duration: Duration::from_millis(100),
        ..Default::default()
    });

    // Fail 3 times
    for _ in 0..3 {
        let _ = cb.call(async { Err::<(), _>("error") }).await;
    }

    // Circuit should be open
    let result = cb.call(async { Ok::<(), ()>(()) }).await;
    assert\!(matches\!(result, Err(CircuitError::Rejected { .. })));
}

#[tokio::test]
async fn test_circuit_breaker_recovers_in_half_open() {
    let cb = CircuitBreaker::new(CircuitBreakerConfig {
        failure_threshold: 2,
        success_threshold: 2,
        open_duration: Duration::from_millis(50),
        ..Default::default()
    });

    // Open the circuit
    for _ in 0..2 {
        let _ = cb.call(async { Err::<(), _>("error") }).await;
    }

    // Wait for open duration
    tokio::time::sleep(Duration::from_millis(60)).await;

    // Should be half-open, allow probe requests
    let result = cb.call(async { Ok(()) }).await;
    assert\!(result.is_ok());

    // One more success closes the circuit
    let result = cb.call(async { Ok(()) }).await;
    assert\!(result.is_ok());

    // Circuit should be closed now
    assert\!(matches\!(cb.state(), CircuitState::Closed));
}

#[tokio::test]
async fn test_bulkhead_limits_concurrency() {
    let bulkhead = Bulkhead::new(BulkheadConfig {
        max_concurrent: 2,
        max_queued: 1,
        queue_timeout: Duration::from_millis(10),
    });

    // Start 4 slow requests
    let handles: Vec<_> = (0..4)
        .map(|_| {
            let bh = bulkhead.clone();
            tokio::spawn(async move {
                bh.call(async {
                    tokio::time::sleep(Duration::from_millis(100)).await;
                    Ok::<(), ()>(())
                }).await
            })
        })
        .collect();

    let results: Vec<_> = futures::future::join_all(handles).await;
    let failures = results.iter()
        .filter(|r| matches\!(r, Ok(Err(_))))
        .count();
    assert\!(failures >= 1, "At least one request should be rejected");
}

#[tokio::test]
async fn test_bulkhead_queues_within_limit() {
    let bulkhead = Bulkhead::new(BulkheadConfig {
        max_concurrent: 1,
        max_queued: 2,
        queue_timeout: Duration::from_secs(5),
    });

    // Start 3 requests (1 running, 2 queued)
    let start = Instant::now();
    let handles: Vec<_> = (0..3)
        .map(|_| {
            let bh = bulkhead.clone();
            tokio::spawn(async move {
                bh.call(async {
                    tokio::time::sleep(Duration::from_millis(50)).await;
                    Ok::<(), ()>(())
                }).await
            })
        })
        .collect();

    let results: Vec<_> = futures::future::join_all(handles).await;
    assert\!(results.iter().all(|r| r.is_ok()));
}

#[tokio::test]
async fn test_health_router_marks_unhealthy() {
    let router = HealthRouter::new(HealthRouterConfig {
        unhealthy_threshold: 3,
        ..Default::default()
    });

    let connector = ConnectorId::new("test");

    // Record 3 failures
    for _ in 0..3 {
        router.record_result(&connector, &RequestResult::Failure {
            error: "error".to_string(),
        });
    }

    // Should be marked unavailable
    let decision = router.can_route(&connector);
    assert\!(matches\!(decision, RoutingDecision::Reject { .. }));
}

#[tokio::test]
async fn test_health_router_recovers_on_success() {
    let router = HealthRouter::new(HealthRouterConfig::default());
    let connector = ConnectorId::new("test");

    // Mark unhealthy
    for _ in 0..5 {
        router.record_result(&connector, &RequestResult::Failure { error: "err".into() });
    }

    // Record successes
    for _ in 0..3 {
        router.record_result(&connector, &RequestResult::Success { latency: Duration::from_millis(10) });
    }

    // Should be healthy again
    assert\!(matches\!(router.can_route(&connector), RoutingDecision::Allow));
}

#[tokio::test]
async fn test_load_shedding_by_priority() {
    let shedder = LoadShedder::new(LoadShedConfig {
        shed_threshold: 0.5,
        full_shed_threshold: 1.0,
        sheddable_priorities: vec\![RequestPriority::Low, RequestPriority::Normal],
        ..Default::default()
    });

    // Set high load
    shedder.set_load(0.9);

    // Critical should never be shed
    let shed_count = (0..100)
        .filter(|_| shedder.should_shed(RequestPriority::Critical))
        .count();
    assert_eq\!(shed_count, 0);

    // Low priority should be shed frequently
    let shed_count = (0..100)
        .filter(|_| shedder.should_shed(RequestPriority::Low))
        .count();
    assert\!(shed_count > 50);
}

