#[tokio::test]
async fn test_cancellation_audit_trail() {
    // Cancellation events are properly audited
    let harness = TestHarness::new().await;

    let op_id = harness.start_slow_operation(Duration::from_secs(60)).await;
    harness.cancel(&op_id, CancelReason::UserRequested, CleanupBehavior::BestEffort).await.unwrap();

    // Check audit log
    let audit_events = harness.get_audit_events(&op_id).await;
    assert!(audit_events.iter().any(|e| e.event == "operation.cancelled"));
}
